export function forceSimulation(nodes=[]){let forces=[];const sim={nodes:()=>nodes,stop:()=>sim,force:(n,f)=>{if(f)forces.push(f);return sim},alpha:()=>sim,alphaMin:()=>sim,alphaDecay:()=>sim,velocityDecay:()=>sim,randomSource:()=>sim,tick:(k=1)=>{for(let i=0;i<k;i++){for(const f of forces)f?.(1);for(const n of nodes){if(n.fx!=null)n.x=n.fx;if(n.fy!=null)n.y=n.fy;n.x+=(n.vx||0);n.y+=(n.vy||0);n.vx=(n.vx||0)*.6;n.vy=(n.vy||0)*.6;}}return sim}};return sim}
export function forceLink(links=[]){let id=d=>d.id,dist=()=>30,str=.1,nodes=[];const f=()=>{const m=new Map(nodes.map(n=>[id(n),n]));for(const l of links){const a=typeof l.source==='object'?l.source:m.get(l.source),b=typeof l.target==='object'?l.target:m.get(l.target);if(!a||!b)continue;const dx=b.x-a.x,dy=b.y-a.y,d=Math.hypot(dx,dy)||1,w=(d-dist(l))/d*str(l);b.vx=(b.vx||0)-dx*w*.5;b.vy=(b.vy||0)-dy*w*.5;a.vx=(a.vx||0)+dx*w*.5;a.vy=(a.vy||0)+dy*w*.5;}};f.id=x=>{id=x;return f};f.distance=x=>{dist=typeof x==='function'?x:()=>x;return f};f.strength=x=>{str=typeof x==='function'?x:()=>x;return f};f.initialize=n=>{nodes=n;return f};return f}
export function forceCollide(r=()=>1){let nodes=[];const rf=typeof r==='function'?r:()=>r;const f=()=>{};f.strength=()=>f;f.iterations=()=>f;f.radius=()=>f;f.initialize=n=>{nodes=n;return f};return f}
export function forceRadial(radius,x=0,y=0){let strength=.1;const rf=typeof radius==='function'?radius:()=>radius;const f=()=>{};f.strength=s=>{strength=s;return f};return f}
export function forceManyBody(){const f=()=>{};f.strength=()=>f;return f}
